import{_ as t,c as a,o as s,a5 as o}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.18.0","description":"NpgsqlRest v3.18.0: The headline of this release is HTTP Custom Type response caching — outbound HTTP calls made by HTTP Custom Types can now be cached and…","frontmatter":{"description":"NpgsqlRest v3.18.0: The headline of this release is HTTP Custom Type response caching — outbound HTTP calls made by HTTP Custom Types can now be cached and…","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.18.0.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.18.0.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.18.0"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.18.0: The headline of this release is HTTP Custom Type response caching — outbound HTTP calls made by HTTP Custom Types can now be cached and…"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.18.0"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.18.0: The headline of this release is HTTP Custom Type response caching — outbound HTTP calls made by HTTP Custom Types can now be cached and…"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.18.0.md","filePath":"guide/changelog/v3.18.0.md","lastUpdated":1782480183000}'),n={name:"guide/changelog/v3.18.0.md"};function r(i,e,c,l,d,h){return s(),a("div",null,e[0]||(e[0]=[o('<h1 id="changelog-v3-18-0" tabindex="-1">Changelog v3.18.0 <a class="header-anchor" href="#changelog-v3-18-0" aria-label="Permalink to &quot;Changelog v3.18.0&quot;">​</a></h1><h2 id="version-3-18-0-2026-06-23" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.18.0" target="_blank" rel="noreferrer">3.18.0</a> (2026-06-23) <a class="header-anchor" href="#version-3-18-0-2026-06-23" aria-label="Permalink to &quot;Version [3.18.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.18.0) (2026-06-23)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.17.0...3.18.0" target="_blank" rel="noreferrer">Full Changelog</a></p><p>The headline of this release is <strong>HTTP Custom Type response caching</strong> — outbound HTTP calls made by HTTP Custom Types can now be cached and reused, eliminating repeated calls to the same upstream within a configurable time window. The release also fixes a duplicate-outbound-call bug for HTTP types on database-function endpoints.</p><h2 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h2><h3 id="http-custom-type-response-caching-—-cache-directive" tabindex="-1">HTTP Custom Type response caching — <code>@cache</code> directive <a class="header-anchor" href="#http-custom-type-response-caching-—-cache-directive" aria-label="Permalink to &quot;HTTP Custom Type response caching — `@cache` directive&quot;">​</a></h3><p>An HTTP Custom Type can now opt into response caching with a <code>@cache</code> directive in its type comment, alongside the existing <code>@timeout</code> and <code>@retry_delay</code> directives. Directives appear <strong>before</strong> the request line:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on type books_api is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;@cache 5m</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">GET https://books.toscrape.com/&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p>A cached type fires <strong>one outbound call</strong> for a given request shape; subsequent matching requests are served from the in-memory cache until the TTL elapses. For a type with no per-request placeholders (a constant URL/headers/body), that means a single shared upstream call per TTL window across the whole application — instead of one call per inbound request.</p><p><strong>Behavior and safety rules:</strong></p><ul><li><strong>Opt-in, GET-only.</strong> Caching is enabled per type by <code>@cache</code>. A <code>@cache</code> directive on any non-GET method is ignored with a startup warning — caching a mutating call is almost always a mistake.</li><li><strong>TTL.</strong> <code>@cache &lt;interval&gt;</code> accepts the same formats as <code>@timeout</code> (<code>5m</code>, <code>30s</code>, <code>1h</code>, <code>00:05:00</code>, or a bare number of seconds). A bare <code>@cache</code> (no interval) caches with no expiration (until the process restarts) and warns.</li><li><strong>Success-only.</strong> Only successful (2xx) responses are cached, so a transient upstream failure is never pinned for the whole TTL — the next request re-fetches.</li><li><strong>Stampede protection.</strong> A burst of concurrent requests for the same cache key coalesces into a <strong>single</strong> outbound call; the rest await the in-flight result (same <code>Lazy&lt;Task&gt;</code> coalescing model as the routine cache).</li><li><strong>Cache key</strong> = HTTP method + resolved URL + resolved content-type + resolved headers + resolved body. Placeholders are resolved first, so per-request values vary the key naturally.</li></ul><p><strong>Configuration</strong> (<code>HttpClientOptions</code>):</p><ul><li><code>CacheEnabled</code> (default <code>true</code>) — global kill switch. When <code>false</code>, <code>@cache</code> directives are ignored and every request fires a fresh call.</li><li><code>MaxCacheEntries</code> (default <code>10000</code>) — bounds memory; once full, new responses are not cached (existing entries still serve and expire normally).</li><li><code>CachePruneIntervalSeconds</code> (default <code>60</code>) — how often expired entries are pruned.</li></ul><h2 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h2><h3 id="http-custom-type-request-fired-once-per-composite-field-on-database-function-endpoints" tabindex="-1">HTTP Custom Type request fired once per composite field on database-function endpoints <a class="header-anchor" href="#http-custom-type-request-fired-once-per-composite-field-on-database-function-endpoints" aria-label="Permalink to &quot;HTTP Custom Type request fired once per composite field on database-function endpoints&quot;">​</a></h3><p>An endpoint backed by a <strong>database function/procedure</strong> whose parameter is an HTTP Custom Type fired <strong>one outbound HTTP call per field of the type</strong> on every inbound request (a 4-field type → 4 identical calls; a 6-field type → 6), multiplying latency and load on the target. SQL-file endpoints were not affected.</p><p><strong>Cause.</strong> A composite function parameter is expanded into one parameter per field, each carrying the same <code>TypeDescriptor.CustomType</code> (the HTTP type name). The per-request list of HTTP types therefore held the same name N times, and the firing loop in <code>HttpClientTypeHandler.InvokeAllAsync</code> called <code>InvokeAsync</code> once per entry — while the fill loop immediately below resolves handlers by <strong>distinct</strong> type name. The design already assumes one call per distinct type; the firing loop just failed to match.</p><p><strong>Fix.</strong> A guard in the firing loop requests each distinct HTTP type once, reusing the dictionary the fill loop already keys on. The established contract is preserved: one call per <strong>distinct</strong> HTTP type, shared from one response — two parameters referencing the same type still share a single call, and two different types remain two separate calls.</p><h3 id="http-type-directives-after-the-headers-were-silently-ignored" tabindex="-1">HTTP type directives after the headers were silently ignored <a class="header-anchor" href="#http-type-directives-after-the-headers-were-silently-ignored" aria-label="Permalink to &quot;HTTP type directives after the headers were silently ignored&quot;">​</a></h3><p>The <code>@timeout</code>, <code>@retry_delay</code>, and <code>@cache</code> directives are now parsed both <strong>before</strong> the request line and <strong>after</strong> the headers. Previously only the leading position (before the request line) was recognized, so a directive placed after the headers — as the documentation and examples showed — was silently dropped (e.g. a <code>@timeout</code> that never applied). Both placements are now equivalent. Real HTTP headers are unaffected: a header whose name merely starts with a directive keyword (e.g. <code>Cache-Control</code>) is still treated as a header.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li>Regression tests count <strong>actual</strong> outbound calls via WireMock response callbacks (the prior suite asserted content but never call counts): a 6-field type fires exactly one call (was 6), and two distinct types fire one call each.</li><li>Caching tests cover: cache hit reduces to one call, 6-field dedup + caching combined, error responses not cached, <code>@cache</code> ignored on POST, and TTL expiry. Parse-level tests cover the <code>@cache</code> directive forms and GET-only enforcement.</li></ul>',22)]))}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
